// Shared risk calculation utilities for both client and server
export interface RiskFactors {
  familyHistory: number;
  lifestyle: number;
  environmental: number;
  age: number;
}

export interface RiskAssessmentResult {
  condition: string;
  riskScore: number;
  riskLevel: 'low' | 'medium' | 'high';
